// Dark Mode Setup (Head)
(function () {
    const yesStorage = () => {
        let storage;
        try {
            storage = window['localStorage'];
            storage.setItem('__rbStorageSet', 'x');
            storage.removeItem('__rbStorageSet');
            return true;
        } catch {
            return false;
        }
    };
    let currentMode = null;
    const darkModeID = 'D_journopulse.io_news';
    currentMode = yesStorage() ? localStorage.getItem(darkModeID) || null : 'default';
    if (!currentMode) {
        currentMode = 'default';
        yesStorage() && localStorage.setItem(darkModeID, 'default');
    }
    // Check if body exists, if not, wait for DOMContentLoaded or just try
    if(document.body) {
        document.body.setAttribute('data-theme', currentMode === 'dark' ? 'dark' : 'default');
    } else {
        // If this script runs in head and body is not ready, we need to handle it. 
        // Original script was inside body tag.
        document.addEventListener('DOMContentLoaded', () => {
             document.body.setAttribute('data-theme', currentMode === 'dark' ? 'dark' : 'default');
        });
    }
})();

// Mailchimp Setup
(function () {
    window.mc4wp = window.mc4wp || {
        listeners: [],
        forms: {
            on: function (evt, cb) {
                window.mc4wp.listeners.push(
                    {
                        event: evt,
                        callback: cb
                    }
                );
            }
        }
    }
})();

// Dark Mode / Privacy / Reading Size Logic
(function () {
    const yesStorage = () => {
        let storage;
        try {
            storage = window['localStorage'];
            storage.setItem('__rbStorageSet', 'x');
            storage.removeItem('__rbStorageSet');
            return true;
        } catch {
            return false;
        }
    };
    const darkModeID = 'D_journopulse.io_news';
    const currentMode = yesStorage() ? (localStorage.getItem(darkModeID) || 'default') : 'default';
    const selector = currentMode === 'dark' ? '.mode-icon-dark' : '.mode-icon-default';
    
    // Wait for DOM if needed, but original was at bottom of body
    const runLogic = () => {
        const icons = document.querySelectorAll(selector);
        if (icons.length) {
            icons.forEach(icon => icon.classList.add('activated'));
        }

        const privacyBox = document.getElementById('rb-privacy');
        const currentPrivacy = yesStorage() ? localStorage.getItem('RubyPrivacyAllowed') || '' : '1';
        if (!currentPrivacy && privacyBox?.classList) {
            privacyBox.classList.add('activated');
        }
        const readingSize = yesStorage() ? sessionStorage.getItem('rubyResizerStep') || '' : '1';
        if (readingSize) {
            const body = document.querySelector('body');
            switch (readingSize) {
                case '2':
                    body.classList.add('medium-entry-size');
                    break;
                case '3':
                    body.classList.add('big-entry-size');
                    break;
            }
        }
    };
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', runLogic);
    } else {
        runLogic();
    }
})();

// URL Input Prefix
(function () {
    function maybePrefixUrlField() {
        const value = this.value.trim()
        if (value !== '' && value.indexOf('http') !== 0) {
            this.value = 'http://' + value
        }
    }

    const urlFields = document.querySelectorAll('.mc4wp-form input[type="url"]')
    for (let j = 0; j < urlFields.length; j++) {
        urlFields[j].addEventListener('blur', maybePrefixUrlField)
    }
})();

// Lazy Load Observer
const lazyloadRunObserver = () => {
    const lazyloadBackgrounds = document.querySelectorAll(`.e-con.e-parent:not(.e-lazyloaded)`);
    const lazyloadBackgroundObserver = new IntersectionObserver((entries) => {
        entries.forEach((entry) => {
            if (entry.isIntersecting) {
                let lazyloadBackground = entry.target;
                if (lazyloadBackground) {
                    lazyloadBackground.classList.add('e-lazyloaded');
                }
                lazyloadBackgroundObserver.unobserve(entry.target);
            }
        });
    }, { rootMargin: '200px 0px 200px 0px' });
    lazyloadBackgrounds.forEach((lazyloadBackground) => {
        lazyloadBackgroundObserver.observe(lazyloadBackground);
    });
};
const events = [
    'DOMContentLoaded',
    'elementor/lazyload/observe',
];
events.forEach((event) => {
    document.addEventListener(event, lazyloadRunObserver);
});

